(111, 'widget_custom_html', 'a:12:{i:4;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:254:\"<img class=\"alignnone size-large wp-image-1200\" src=\"https://themedemo.commercegurus.com/shoptimizer-demodata/wp-content/uploads/sites/53/2018/07/trust-symbols_b-1024x108.jpg\" alt=\"Chili termékek-chilimánia-Chili Hungária\" width=\"1024\" height=\"108\" />\";}i:5;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:414:\"<h4>Rólunk mondták</h4>\r\n<img class=\"alignleft wp-image-829 size-thumbnail\" style=\"width: 60px; \r\nborder-radius: 50%; margin-right: 1.5em;\" src=\"https://themedemo.commercegurus.com/shoptimizer/wp-content/uploads/sites/52/2018/05/reviews02-150x150.jpg\" alt=\"Chili termékek-chilimánia-Chili Hungária\" width=\"150\" height=\"150\" />Az ügyfélszolgálat minősége és a kézbesítés sebessége fantasztikus volt\r\n\";}i:6;a:2:{s:5:\"title\";s:17:\"Kupon kedvezmény\";s:7:\"content\";s:497:\"<p>29 990 Ft-os vásárlás esetén azonnal beváltható 1 000 Ft kedvezményt kapsz egy kupon segítségével.\r\n</p>\r\n\r\n<svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewbox=\"0 0 24 24\" stroke=\"currentColor\">\r\n	<path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z\" />\r\n	<path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M15 11a3 3 0 11-6 0 3 3 0 016 0z\" />\r\n</svg>\";}i:7;a:2:{s:5:\"title\";s:20:\"Személyes átvétel\";s:7:\"content\";s:285:\"<p>\r\n	1136 Budapeset, Hegedűs Gyula utca 32.\r\n</p>\r\n\r\n<svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewbox=\"0 0 24 24\" stroke=\"currentColor\">\r\n	<path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4\" />\r\n</svg>\";}i:8;a:2:{s:5:\"title\";s:45:\"Megbízható szállítás | GLS futárcéggel\";s:7:\"content\";s:441:\"<p>\r\nRendelésedet 2 munkanapon belül kiszállítjuk.\r\n</p>\r\n\r\n<svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewbox=\"0 0 24 24\" stroke=\"currentColor\">\r\n<path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z\" />\r\n</svg>\";}i:9;a:2:{s:5:\"title\";s:31:\"Worldline biztonságos fizetés\";s:7:\"content\";s:324:\"<p>\r\nQuickpay / MasterCard / Visa\r\n</p>\r\n\r\n<svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewbox=\"0 0 24 24\" stroke=\"currentColor\">\r\n<path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z\" />\r\n</svg>\";}i:10;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:24:\"Bp. Hegedűs Gyula u 32.\";}i:12;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:37:\"\r\nÜgyfélszolgálat: +36-30-478-8101\";}i:14;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:238:\"<li id=\"menu-item-13381\" class=\"szerviz menu-item menu-item-type-post_type menu-item-object-page menu-item-13381\"><a href=\"https://chilimania.hu/chili-palanta-szerviz/\"><span style=\"color: #ffffff;\">Chili palánta szervíz</span></a></li>\";}i:15;a:2:{s:5:\"title\";s:10:\"HÍRLEVÉL\";s:7:\"content\";s:1535:\"Iratkozz fel hírlevelünkre, és zsebeld be a 5% kedvezményed!\r\n<form action=\"https://admin.dimail.hu/external/form/\" method=\"post\" name=\"newsletter-342-form\">\r\n	<input type=\"hidden\" name=\"list\" value=\"fde50cca1ffbab4493b694cf7f38ab52fffa0dc1\" />\r\n	<input type=\"hidden\" name=\"onSuccess\" value=\"\" />\r\n	<input type=\"hidden\" name=\"onError\" value=\"\" />\r\n	<input type=\"hidden\" name=\"acceptPrivacyPolicyCheck\" value=\"true\" />\r\n	<label for=\"newsletter-342-form-name\">Név:</label>\r\n	<input id=\"newsletter-342-form-name\" type=\"text\" name=\"subscriberName\" placeholder=\"Teljes név vagy becenév\" />\r\n	<label for=\"newsletter-342-form-email\">E-mail cím:</label>\r\n	<input id=\"newsletter-342-form-email\" type=\"text\" name=\"subscriberEmail\" placeholder=\"E-mail cím\" />\r\n	<label for=\"newsletter-342-form-pp\">Elfogadom az <a href=\"https://chilimania.hu/hasznos-informaciok/#1531589717698-89f74239-719b\" target=\"_blank\">adatkezelési nyilatkozatot</a>.</label>\r\n	<input id=\"newsletter-342-form-pp\" type=\"checkbox\" name=\"acceptPrivacyPolicy\" value=\"true\" onclick=\"_dimail_terms_changed_342(this)\" />\r\n	<p>\r\n		<button id=\"newsletter-342-form-submit\" type=\"submit\" name=\"subscribe\" value=\"true\" disabled>Feliratkozás a hírlevélre</button>\r\n	</p>\r\n</form>\r\n<script>if(typeof _dimail_terms_changed_342!==\'function\') var _dimail_terms_changed_342=function(termsCheckBox){if(termsCheckBox.checked)document.getElementById(\"newsletter-342-form-submit\").disabled=false;else document.getElementById(\"newsletter-342-form-submit\").disabled=true;}</script>\r\n\r\n\";}i:17;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:326:\"<script id=\"barat_hud_sr_script\">var hst = document.createElement(\"script\");hst.src = \"//admin.fogyasztobarat.hu/h-api.js\";hst.type = \"text/javascript\";hst.setAttribute(\"data-id\", \"31TGVG81\");hst.setAttribute(\"id\", \"fbarat\");var hs = document.getElementById(\"barat_hud_sr_script\");hs.parentNode.insertBefore(hst, hs);</script>\";}s:12:\"_multiwidget\";i:1;}', 'on'),
