(454649, 'wpgv_emailsubject', '<span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">Megrendelés megerősítése - A (z) {company_name} megrendeléssel (utalvány megrendelési száma: {order_number}) sikeresen megtörtént!</span></span>', 'yes'),
(454650, 'wpgv_emailbody', '<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Kedves </span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{customer_name}</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> !</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">A rendelés sikeresen elküldve.</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Örömmel erősítjük meg, hogy megrendelése nem {order_number}</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Köszönjük, hogy vásárolt a (z) </span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{company_name} céggel</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> !</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Az utalványt letöltheti a (z) {pdf_link} oldalról.</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">- Ha bármilyen pontosításra van szüksége, kérjük, írjon nekünk e-mailt a (z) {sender_email} címre.</span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Üdvözlettel </span></span><br /></strong> <strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{COMPANY_NAME} </span></span><br /><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{WEBSITE_URL}</span></span></strong></p>', 'yes'),
(454651, 'wpgv_emailbodyperinvoice', '<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Kedves </span></span></span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{customer_name}</span></span></span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> !</span></span></span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">A rendelés sikeresen elküldve.</span></span></span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Örömmel erősítjük meg, hogy megrendelése nem {order_number}</span></span></span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Köszönjük, hogy vásárolt a (z) </span></span></span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{company_name} céggel</span></span></span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> !</span></span></span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Az utalványt letöltheti a (z) {pdf_link} oldalról.</span></span></span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Fizetni fog nekünk közvetlenül a bankba. </span><span style=\"vertical-align: inherit\">Bankinformációink az alábbiakban találhatók:</span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Számlaszám:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> XXXXXXXXXXXX bankkód </span></span><br /><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> XXXXXXXX</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">- Ha bármilyen pontosításra van szüksége, kérjük, írjon nekünk e-mailt a (z) {sender_email} címre.</span></span></span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Üdvözlettel </span></span></span></span><br /></strong> <strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{COMPANY_NAME} </span></span></span></span><br /><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{WEBSITE_URL}</span></span></span></span></strong></p>', 'yes'),
(454652, 'wpgv_recipientemailsubject', '<span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">Ajándék utalvány - Ön kapott utalványt a (z) {company_name} cégtől</span></span>', 'yes'),
(454653, 'wpgv_recipientemailbody', '<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Kedves </span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{recip_name}</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> !</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Ajándékutalványt kapott a következőtől:  </span></span><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{customer_name}</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> .</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Az utalványt letöltheti a (z) {pdf_link} oldalról.</span></span></p>\r\n<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">- Ha bármilyen pontosításra van szüksége, kérjük, írjon nekünk e-mailt a (z) {sender_email} címre.</span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Üdvözlettel </span></span><br /></strong> <strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{COMPANY_NAME} </span></span><br /><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">{WEBSITE_URL}</span></span></strong></p>', 'yes'),
(454654, 'wpgv_adminemailsubject', 'Új utalványmegrendelés érkezett a (z) {customer_name} -tól (Rendelési szám: {order_number})!', 'yes'),
(454655, 'wpgv_adminemailbody', '<p><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Üdvözlet, új utalványos megrendelés érkezett.</span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Megrendelés azonosítója:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> {order_number}</span></span></p>\r\n<p><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Név:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> {customer_name} </span></span><br /><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">E-mail:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> {customer_email} </span></span><br /><strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\">Összeg:</span></span></strong><span style=\"vertical-align: inherit\"><span style=\"vertical-align: inherit\"> {suma}</span></span></p>', 'yes'),
(454656, 'wpgv_successpagemessage', '<p><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">Megvan a megrendelésünk! </span></span><br /><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">E-mail sikeresen elküldve a következőnek:% s. </span></span><br /><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">Ez a link 1 óra után érvénytelen lesz.</span></span></p>', 'yes'),
(454657, 'wpgv_cancelpagemessage', '<p><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">Ön törölte a rendelését. </span><span style=\\\"vertical-align: inherit;\\\">Kérjük, </span></span><a href=\\\"https://chilimania.hu/gift-voucher\\\"><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\">itt</span></span></a><span style=\\\"vertical-align: inherit;\\\"><span style=\\\"vertical-align: inherit;\\\"> küldje újra megrendelését </span><span style=\\\"vertical-align: inherit;\\\">.</span></span></p>', 'yes'),
